5	import { TopicDefinition, resolveTopic } from "./topics.js";
6	import { Prng } from "./random.js";
7	
8	export type QuestionType = "multiple_choice" | "short_answer" | "true_false" | "fill_in" | "transfer";
9	
10	export interface QuizQuestion {
11	  id: string;
12	  type: QuestionType;
13	  level: "recall" | "comprehension" | "application" | "analysis" | "transfer";
14	  question: string;
15	  options?: string[]; // For multiple_choice, true_false
16	  correctAnswer: string;
17	  explanation: string;
18	  rubric?: string; // For short_answer / transfer
19	}
20	
21	export interface QuizReview {
22	  status: "passed" | "revised";
23	  issues: string[];
24	  duplicatesRemoved: number;
25	  maxQuestionChars: number;
26	  maxAnswerChars: number;
27	  maxExplanationChars: number;
28	  maxRubricChars: number;
29	  maxOptionChars: number;
30	  limits: QuizLimits;
31	}
