41	}
42	
43	export interface WorkbookSection {
44	  title: string;
45	  instructions: string;
46	  questions: QuizQuestion[];
47	}
48	
49	export interface Workbook {
50	  topic: string;
51	  slug: string;
52	  sections: WorkbookSection[];
53	  generatedAt: string;
54	}
55	
56	export interface QuizLimits {
57	  questionChars: number;
58	  answerChars: number;
59	  explanationChars: number;
60	  rubricChars: number;
61	  optionChars: number;
62	}
63	
64	export type QuizLimitOverrides = Partial<QuizLimits>;
65	
66	export interface GenerateQuizOptions {
67	  limits?: QuizLimitOverrides;
68	}
69	
70	// ─── Question Generation ──────────────────────────────────────────────────
71	
72	const DEFAULT_QUIZ_LIMITS: QuizLimits = {
73	  questionChars: 180,
74	  answerChars: 220,
75	  explanationChars: 220,
76	  rubricChars: 120,
77	  optionChars: 140,
78	};
79	
80	function clampLimit(value: number | undefined, min: number, max: number, fallback: number): number {
81	  if (value === undefined || !Number.isFinite(value)) return fallback;
82	  return Math.max(min, Math.min(max, Math.round(value)));
83	}
84	
85	export function resolveQuizLimits(overrides: QuizLimitOverrides = {}): QuizLimits {
86	  return {
87	    questionChars: clampLimit(overrides.questionChars, 80, 320, DEFAULT_QUIZ_LIMITS.questionChars),
88	    answerChars: clampLimit(overrides.answerChars, 80, 500, DEFAULT_QUIZ_LIMITS.answerChars),
89	    explanationChars: clampLimit(overrides.explanationChars, 80, 500, DEFAULT_QUIZ_LIMITS.explanationChars),
90	    rubricChars: clampLimit(overrides.rubricChars, 60, 220, DEFAULT_QUIZ_LIMITS.rubricChars),
91	    optionChars: clampLimit(overrides.optionChars, 40, 220, DEFAULT_QUIZ_LIMITS.optionChars),
92	  };
93	}
94	
95	function limitText(value: string, maxChars: number): string {
96	  const text = value.replace(/\s+/g, " ").trim();
97	  if (text.length <= maxChars) return text;
98	  const clipped = text.slice(0, Math.max(0, maxChars - 1)).trimEnd();
99	  const boundary = Math.max(clipped.lastIndexOf("."), clipped.lastIndexOf(";"), clipped.lastIndexOf(","));
100	  const shortened = boundary >= maxChars * 0.6 ? clipped.slice(0, boundary) : clipped;
101	  return `${shortened.trimEnd()}…`;
102	}
103	
104	function pickDistinct(items: string[], prng: Prng, idx: number, fallback: string): string {
105	  const clean = items.map((item) => item.trim()).filter(Boolean);
106	  if (clean.length === 0) return fallback;
107	  const start = prng.int(0, clean.length - 1);
108	  return clean[(start + idx - 1) % clean.length] ?? fallback;
109	}
110	
111	function normalizeQuestion(value: string): string {
112	  return value
113	    .toLowerCase()
114	    .replace(/["'`]/g, "")
115	    .replace(/[^a-z0-9\s]/g, " ")
116	    .split(/\s+/)
117	    .filter((word) => word.length > 2 && !["the", "and", "for", "with", "your", "this", "that", "about"].includes(word))
118	    .join(" ");
119	}
120	
121	function tokenSimilarity(a: string, b: string): number {
122	  const left = new Set(normalizeQuestion(a).split(/\s+/).filter(Boolean));
123	  const right = new Set(normalizeQuestion(b).split(/\s+/).filter(Boolean));
124	  if (left.size === 0 || right.size === 0) return 0;
125	  let intersection = 0;
126	  for (const token of left) {
127	    if (right.has(token)) intersection++;
128	  }
129	  return intersection / (left.size + right.size - intersection);
130	}
131	
132	function enforceQuestionLimits(q: QuizQuestion, limits: QuizLimits): QuizQuestion {
133	  return {
134	    ...q,
135	    question: limitText(q.question, limits.questionChars),
136	    correctAnswer: limitText(q.correctAnswer, limits.answerChars),
137	    explanation: limitText(q.explanation, limits.explanationChars),
138	    rubric: q.rubric ? limitText(q.rubric, limits.rubricChars) : undefined,
139	    options: q.options?.map((option) => limitText(option, limits.optionChars)),
140	  };
141	}
142	
143	function reviewQuizQuestions(questions: QuizQuestion[], limits: QuizLimits): QuizReview {
144	  const issues: string[] = [];
145	  let duplicatesRemoved = 0;
146	  const seen: QuizQuestion[] = [];
147	
148	  for (const q of questions) {
149	    if (q.question.length > limits.questionChars) issues.push(`${q.id}: question exceeded ${limits.questionChars} chars`);
150	    if (q.correctAnswer.length > limits.answerChars) issues.push(`${q.id}: answer exceeded ${limits.answerChars} chars`);
151	    if (q.explanation.length > limits.explanationChars) issues.push(`${q.id}: explanation exceeded ${limits.explanationChars} chars`);
152	    if (q.rubric && q.rubric.length > limits.rubricChars) issues.push(`${q.id}: rubric exceeded ${limits.rubricChars} chars`);
153	    for (const option of q.options ?? []) {
154	      if (option.length > limits.optionChars) issues.push(`${q.id}: option exceeded ${limits.optionChars} chars`);
155	    }
156	    if (seen.some((prior) => tokenSimilarity(prior.question, q.question) >= 0.82)) {
157	      duplicatesRemoved++;
158	      issues.push(`${q.id}: similar to an earlier question`);
159	    } else {
160	      seen.push(q);
161	    }
162	  }
163	
164	  return {
165	    status: issues.length === 0 ? "passed" : "revised",
166	    issues,
167	    duplicatesRemoved,
168	    maxQuestionChars: limits.questionChars,
169	    maxAnswerChars: limits.answerChars,
170	    maxExplanationChars: limits.explanationChars,
171	    maxRubricChars: limits.rubricChars,
172	    maxOptionChars: limits.optionChars,
173	    limits,
174	  };
175	}
176	
177	function refineQuizQuestions(questions: QuizQuestion[], limits: QuizLimits): { questions: QuizQuestion[]; review: QuizReview } {
178	  const refined = questions.map((question) => enforceQuestionLimits(question, limits));
179	  const review = reviewQuizQuestions(refined, limits);
180	  return { questions: refined, review };
181	}
182	
183	function makeRecallQ(topic: TopicDefinition, _prng: Prng, idx: number): QuizQuestion {
184	  return {
185	    id: `${topic.slug}-r${idx}`,
186	    type: "short_answer",
187	    level: "recall",
188	    question: idx === 1
189	      ? `Define "${topic.title}" in your own words.`
190	      : `State the central idea of ${topic.title} without using the exact lesson wording.`,
191	    correctAnswer: topic.summary,
192	    explanation: `The core definition: ${topic.summary}`,
193	    rubric: `1pt vague, 2pts essence, 3pts precise with nuance.`,
194	  };
195	}
196	
197	function makeComprehensionQ(topic: TopicDefinition, prng: Prng, idx: number): QuizQuestion {
198	  const hook = pickDistinct(topic.intuition, prng, idx, "the concept");
199	  return {
200	    id: `${topic.slug}-c${idx}`,
201	    type: "short_answer",
202	    level: "comprehension",
203	    question: `Explain the intuition: "${hook}". Why is this a helpful way to think about ${topic.title}?`,
204	    correctAnswer: `Because it maps ${topic.title} to something concrete before formal notation.`,
205	    explanation: `Intuition first, formalism second: ${hook}`,
206	    rubric: `2pts: explains the metaphor. 3pts: identifies when it breaks down.`,
207	  };
208	}
209	
210	function makeApplicationQ(topic: TopicDefinition, prng: Prng, idx: number): QuizQuestion {
211	  const ex = pickDistinct(topic.examples, prng, idx, `an example involving ${topic.title}`);
212	  return {
213	    id: `${topic.slug}-a${idx}`,
214	    type: "short_answer",
215	    level: "application",
216	    question: idx === 1
217	      ? `Work through this example: ${ex}. Show the key reasoning steps.`
218	      : `Use ${topic.title} to solve or analyze this case: ${ex}. Name the rule you used.`,
219	    correctAnswer: `Follow the mechanics demonstrated in ${topic.title}.`,
220	    explanation: `Application grounds abstract knowledge: ${ex}`,
221	    rubric: `2pts attempt, 3pts correct mechanics, 4pts clear reasoning.`,
222	  };
223	}
224	
225	function makeMisconceptionQ(topic: TopicDefinition, prng: Prng, idx: number): QuizQuestion {
226	  const mis = topic.misconceptions;
227	  const m = mis[prng.int(0, mis.length - 1)] ?? "a common misconception";
228	  return {
229	    id: `${topic.slug}-m${idx}`,
230	    type: "multiple_choice",
231	    level: "comprehension",
232	    question: `Which of the following statements about ${topic.title} is FALSE?`,
233	    options: [
234	      `${m}`,
235	      `${topic.title} can be reasoned about using concrete examples.`,
236	      `A good answer should mention limits or boundary conditions.`,
237	      `The formal version should connect back to the intuition.`,
238	    ],
239	    correctAnswer: `${m}`,
240	    explanation: `"${m}" is a known misconception. The other statements are generally true.`,
241	  };
242	}
243	
244	function makeTransferQ(topic: TopicDefinition, prng: Prng, idx: number): QuizQuestion {
245	  const domain = pickDistinct(topic.interdisciplinaryHooks, prng, idx, "a new domain");
246	  return {
247	    id: `${topic.slug}-t${idx}`,
248	    type: "short_answer",
249	    level: "transfer",
250	    question: idx === 1
251	      ? `Apply ${topic.title} to ${domain}. What structure carries over?`
252	      : `Where would an analogy between ${topic.title} and ${domain} break down?`,
253	    correctAnswer: `A valid analogy that preserves structural relationships and acknowledges boundary conditions.`,
254	    explanation: `Transfer requires mapping invariants, not surface features, to ${domain}.`,
255	    rubric: `2pts surface analogy, 3pts structure, 4pts limits included.`,
256	  };
257	}
258	
259	export function generateQuiz(topicName: string, seed = 42, options: GenerateQuizOptions = {}): Quiz {
260	  const topic = resolveTopic(topicName);
261	  const prng = new Prng(seed);
262	  const limits = resolveQuizLimits(options.limits);
263	  const questions: QuizQuestion[] = [];
264	
265	  // 2 recall
266	  questions.push(makeRecallQ(topic, prng, 1));
267	  questions.push(makeRecallQ(topic, prng, 2));
268	  // 2 comprehension
269	  questions.push(makeComprehensionQ(topic, prng, 1));
270	  questions.push(makeMisconceptionQ(topic, prng, 1));
271	  // 2 application
272	  questions.push(makeApplicationQ(topic, prng, 1));
273	  questions.push(makeApplicationQ(topic, prng, 2));
274	  // 2 transfer
275	  questions.push(makeTransferQ(topic, prng, 1));
276	  questions.push(makeTransferQ(topic, prng, 2));
277	
278	  const refined = refineQuizQuestions(questions, limits);
279	  const answerKey = new Map<string, string>();
280	  for (const q of refined.questions) {
281	    answerKey.set(q.id, q.correctAnswer);
282	  }
283	
284	  return {
285	    topic: topic.title,
286	    slug: topic.slug,
287	    generatedAt: new Date().toISOString(),
288	    questions: refined.questions,
289	    answerKey,
290	    totalPoints: refined.questions.reduce((s, q) => s + (q.rubric ? 3 : 1), 0),
291	    review: refined.review,
292	  };
293	}
294	
295	// ─── Workbook ─────────────────────────────────────────────────────────────
296	
297	export function generateWorkbook(topicName: string, seed = 42): Workbook {
298	  const topic = resolveTopic(topicName);
299	  const prng = new Prng(seed);
300	  const quiz = generateQuiz(topicName, seed);
301	
302	  const sections: WorkbookSection[] = [
303	    {
304	      title: "Part A: Foundation",
305	      instructions: "Answer every question without looking at notes. Retrieval practice beats re-reading.",
306	      questions: quiz.questions.filter(q => q.level === "recall" || q.level === "comprehension"),
307	    },
308	    {
309	      title: "Part B: Application",
310	      instructions: "Work each example out on paper or in a text editor. Show all steps.",
311	      questions: quiz.questions.filter(q => q.level === "application"),
312	    },
313	    {
314	      title: "Part C: Transfer",
315	      instructions: "Bridge this concept into unfamiliar territory. If your analogy feels too easy, it is probably too shallow.",
316	      questions: quiz.questions.filter(q => q.level === "transfer"),
317	    },
318	  ];
319	
320	  return {
321	    topic: topic.title,
322	    slug: topic.slug,
323	    sections,
324	    generatedAt: new Date().toISOString(),
325	  };
326	}
327	
328	// ─── Markdown output ──────────────────────────────────────────────────────
329	
330	export function quizToMarkdown(quiz: Quiz): string {
331	  const lines = [
332	    `# Quiz: ${quiz.topic}`,
333	    `> Generated: ${quiz.generatedAt}`,
334	    `> Reviewed: ${quiz.review.status}; limits q/a/expl/rubric/option ${quiz.review.maxQuestionChars}/${quiz.review.maxAnswerChars}/${quiz.review.maxExplanationChars}/${quiz.review.maxRubricChars}/${quiz.review.maxOptionChars} chars`,
335	    ``,
336	  ];
337	  for (const q of quiz.questions) {
338	    lines.push(`## ${q.id} — ${q.level} (${q.type})`);
339	    lines.push(q.question);
340	    if (q.options) {
341	      lines.push("");
342	      for (let i = 0; i < q.options.length; i++) {
343	        lines.push(`${String.fromCharCode(65 + i)}. ${q.options[i]}`);
344	      }
345	    }
346	    lines.push("");
347	    if (q.rubric) lines.push(`*Rubric:* ${q.rubric}`);
348	    lines.push("");
349	  }
350	  return lines.join("\n") + "\n";
351	}
352	
353	export function quizAnswerKeyToMarkdown(quiz: Quiz): string {
354	  const lines = [
355	    `# Answer Key: ${quiz.topic}`,
356	    "",
357	  ];
358	  for (const q of quiz.questions) {
359	    lines.push(`## ${q.id}`);
360	    lines.push(`**Answer:** ${q.correctAnswer}`);
361	    lines.push(`**Explanation:** ${q.explanation}`);
362	    lines.push("");
363	  }
364	  return lines.join("\n") + "\n";
365	}
366	
367	export function workbookToMarkdown(wb: Workbook): string {
368	  const lines = [
369	    `# Workbook: ${wb.topic}`,
370	    `> Self-paced. Do Part A in one sitting, Part B after a break, Part C tomorrow.`,
371	    "",
372	  ];
373	  for (const section of wb.sections) {
374	    lines.push(`---`);
375	    lines.push(`# ${section.title}`);
376	    lines.push(section.instructions);
377	    lines.push("");
378	    for (const q of section.questions) {
379	      lines.push(`### ${q.id} — ${q.level}`);
380	      lines.push(q.question);
381	      if (q.options) {
382	        for (let i = 0; i < q.options.length; i++) {
383	          lines.push(`${String.fromCharCode(65 + i)}. ${q.options[i]}`);
384	        }
385	      }
386	      lines.push("");
387	      lines.push(`*Space for answer:*`);
388	      lines.push("\n\n\n\n"); // Blank space
389	    }
390	  }
391	  return lines.join("\n") + "\n";
392	}
