512	function shuffleWithSeed<T>(items: T[], seed: number): T[] {
513		const copy = [...items];
514		let state = Math.max(1, seed | 0);
515		for (let i = copy.length - 1; i > 0; i--) {
516			state = (state * 1103515245 + 12345) & 0x7fffffff;
517			const j = state % (i + 1);
518			[copy[i], copy[j]] = [copy[j], copy[i]];
519		}
520		return copy;
521	}
