523	function optionSet(correct: string, distractors: string[], seed: number, fallbackLabel = "None of the above"): string[] {
524		const seen = new Set<string>();
525		const options = [correct, ...distractors, fallbackLabel]
526			.map(stripMarkdown)
527			.filter((item) => {
528				if (item.length < 3 || seen.has(item.toLowerCase())) return false;
529				seen.add(item.toLowerCase());
530				return true;
531			})
532			.slice(0, 4);
533		while (options.length < 4) {
534			options.push(`Related but not the best answer ${options.length}`);
535		}
536		return shuffleWithSeed(options, seed);
537	}
