539	function extractPlanSummary(content: string): string {
540		const summary = content.match(/^- Summary:\s*(.+)$/im)?.[1]?.trim();
541		if (summary) return stripMarkdown(summary);
542		const firstParagraph = content
543			.split(/\n{2,}/)
544			.map((part) => stripMarkdown(part))
545			.find((part) => part && !part.startsWith("#") && !part.startsWith("- Domain:"));
546		return firstParagraph ?? "the central idea of this lesson";
547	}
