549	function extractPlanSections(content: string): PlanQuizSection[] {
550		const sections: PlanQuizSection[] = [];
551		const headingPattern = /^##\s+(.+)$/gm;
552		const matches = Array.from(content.matchAll(headingPattern));
553	
554		for (let i = 0; i < matches.length; i++) {
555			const match = matches[i];
556			const title = stripMarkdown(match[1] ?? "");
557			const start = (match.index ?? 0) + match[0].length;
558			const end = i + 1 < matches.length ? matches[i + 1].index ?? content.length : content.length;
559			const body = content.slice(start, end).trim();
560			const lines = body.split("\n").map((line) => line.trim()).filter(Boolean);
561			const purpose = stripMarkdown(lines.find((line) => !line.startsWith("- ")) ?? "");
562			const bullets = lines.filter((line) => line.startsWith("- ")).map(stripMarkdown);
563			if (title && (purpose || bullets.length > 0)) {
564				sections.push({ index: i, title, purpose, bullets });
565			}
566		}
567	
568		return sections;
569	}
