587			type: "multiple_choice",
588			level: "recall",
589			question: `Which statement best captures the main point of this lesson plan?`,
590			options: optionSet(
591				summary,
592				[
593					`The lesson is mainly a list of unrelated facts about ${plan.topic}.`,
594					`The lesson avoids practice and only asks the learner to read.`,
595					`The lesson is only concerned with provider setup and app navigation.`,
596				],
597				seed + 1,
598			),
599			correctAnswer: summary,
600			explanation: `This comes from the saved lesson summary for ${plan.topic}.`,
601		});
602	
