604			const correct = section.bullets[seed % section.bullets.length] ?? section.purpose;
605			const distractors = allBullets
606				.filter((item) => item.section.index !== section.index)
607				.map((item) => item.bullet);
608			questions.push({
609				id: `${slug}-plan-section-${section.index}-${seed}`,
610				type: "multiple_choice",
611				level: section.index < 2 ? "comprehension" : section.title.toLowerCase().includes("practice") ? "application" : "analysis",
612				question: `In the "${section.title}" part of the plan, which move should the tutor make?`,
613				options: optionSet(correct, distractors, seed + section.index + 10),
614				correctAnswer: correct,
615				explanation: `The "${section.title}" section says: ${correct}`,
616			});
617		}
618	
619		const multiSelectSections = orderedSections.filter((section) => section.bullets.length >= 2);
620		const multiSection = multiSelectSections[seed % multiSelectSections.length];
621		if (multiSection) {
622			const correctAnswers = multiSection.bullets.slice(0, 2);
623			const distractors = allBullets
624				.filter((item) => item.section.index !== multiSection.index)
625				.map((item) => item.bullet);
626			questions.push({
627				id: `${slug}-plan-multi-${multiSection.index}-${seed}`,
628				type: "multi_select",
629				level: "application",
630				question: `Select the two actions that belong in "${multiSection.title}".`,
631				options: optionSet(correctAnswers[0], [correctAnswers[1], ...distractors], seed + 100, "Skip this action"),
632				correctAnswer: correctAnswers.join(", "),
