		maxExplanationChars: 220,
		maxRubricChars: 120,
		maxOptionChars: 140,
		limits: {
			questionChars: 180,
			answerChars: 220,
			explanationChars: 220,
			rubricChars: 120,
			optionChars: 140,
		},
	};
}

