export type QuizLimitOverrides = Partial<QuizLimits>;

export interface GenerateQuizOptions {
  limits?: QuizLimitOverrides;
}

// ─── Question Generation ──────────────────────────────────────────────────

const DEFAULT_QUIZ_LIMITS: QuizLimits = {
  questionChars: 180,
  answerChars: 220,
  explanationChars: 220,
  rubricChars: 120,
  optionChars: 140,
};

