1065					limits: {
1066						type: "object",
1067						description: "Optional concise output limits chosen for this quiz. Values are clamped to safe ranges.",
1068						properties: {
1069							question_chars: { type: "number", description: "Maximum characters per question, clamped to 80-320." },
1070							answer_chars: { type: "number", description: "Maximum characters per answer, clamped to 80-500." },
1071							explanation_chars: { type: "number", description: "Maximum characters per explanation, clamped to 80-500." },
1072							rubric_chars: { type: "number", description: "Maximum characters per rubric, clamped to 60-220." },
1073							option_chars: { type: "number", description: "Maximum characters per multiple-choice option, clamped to 40-220." },
