1078				async (params) => {
1079					const topic = (params.topic as string) || "";
1080					if (!topic) return "Topic required.";
1081	
1082					const reframeModes = Array.isArray(params.reframes)
1083						? params.reframes.filter((r): r is string => typeof r === "string")
1084						: undefined;
1085					const rawLimits = params.limits && typeof params.limits === "object"
1086						? params.limits as Record<string, unknown>
1087						: undefined;
1088					const authored = Array.isArray(params.questions)
1089						? (params.questions as unknown[])
1090							.filter((q): q is Record<string, unknown> => !!q && typeof q === "object")
1091							.map((q) => ({
