			question: `Use your own words: how would you apply the "${transfer.title}" part of this plan after taking the lesson?`,
			correctAnswer: transfer.bullets[0] ?? transfer.purpose,
			explanation: `A strong answer should connect back to this saved lesson move: ${transfer.bullets[0] ?? transfer.purpose}`,
			rubric: "2pts: names the relevant move. 3pts: applies it to a new example. 4pts: applies it and names a limit.",
		});
	}

	const refinedQuestions = questions.map((q) => ({
		...q,
		question: limitPlanQuizText(q.question, 180),
		correctAnswer: limitPlanQuizText(q.correctAnswer, 220),
		explanation: limitPlanQuizText(q.explanation, 220),
		rubric: q.rubric ? limitPlanQuizText(q.rubric, 120) : undefined,
		options: q.options?.map((option) => limitPlanQuizText(option, 140)),
	}));
	const review = reviewPlanQuiz(refinedQuestions);

	return {
		topic: plan.topic,
		slug: `${slug}-lesson-plan`,
		generatedAt: new Date().toISOString(),
		questions: refinedQuestions,
		totalPoints: refinedQuestions.reduce((sum, q) => sum + (q.rubric ? 3 : q.type === "multi_select" ? 2 : 1), 0),
		adaptiveRules: [
			{ level: "recall", threshold: 0.5 },
			{ level: "comprehension", threshold: 0.5 },
			{ level: "application", threshold: 0.5 },
			{ level: "analysis", threshold: 0.5 },
			{ level: "transfer", threshold: 0.5 },
		],
		review,
	};
}

function limitPlanQuizText(value: string, maxChars: number): string {
	const text = value.replace(/\s+/g, " ").trim();
	if (text.length <= maxChars) return text;
	const clipped = text.slice(0, Math.max(0, maxChars - 1)).trimEnd();
	const boundary = Math.max(clipped.lastIndexOf("."), clipped.lastIndexOf(";"), clipped.lastIndexOf(","));
	const shortened = boundary >= maxChars * 0.6 ? clipped.slice(0, boundary) : clipped;
	return `${shortened.trimEnd()}…`;
}

function reviewPlanQuiz(questions: QuizQuestion[]): QuizReview {
	const issues: string[] = [];
	for (const q of questions) {
		if (q.question.length > 180) issues.push(`${q.id}: question exceeded 180 chars`);
		if (q.correctAnswer.length > 220) issues.push(`${q.id}: answer exceeded 220 chars`);
		if (q.explanation.length > 220) issues.push(`${q.id}: explanation exceeded 220 chars`);
	}
	return {
		status: issues.length === 0 ? "passed" : "revised",
		issues,
		duplicatesRemoved: 0,
		maxQuestionChars: 180,
		maxAnswerChars: 220,
		maxExplanationChars: 220,
		maxRubricChars: 120,
		maxOptionChars: 140,
		limits: {
			questionChars: 180,
			answerChars: 220,
			explanationChars: 220,
			rubricChars: 120,
			optionChars: 140,
		},
	};
}

function missedSectionIndexes(result: QuizResult | null): number[] {
	if (!result) return [];
	const missed = new Set<number>();
	for (const [questionId, credit] of Object.entries(result.partialCredits)) {
		if (credit >= 1) continue;
		const match = questionId.match(/-plan-(?:section|multi|transfer)-(\d+)-/);
		if (match) missed.add(Number(match[1]));
	}
	return Array.from(missed);
}

